function solve(nums) {
    const N = nums.length;
    if (N === 0) {
        return [];
    }
    if (N === 1) {
        return nums;
    }

    // Step 1: Calculate max_left[i] = max(nums[0]...nums[i-1])
    const maxLeft = new Array(N);
    // Initialize M_L[0] to negative infinity as there are no elements to the left of index 0
    maxLeft[0] = Number.NEGATIVE_INFINITY;
    for (let i = 1; i < N; i++) {
        maxLeft[i] = Math.max(maxLeft[i - 1], nums[i - 1]);
    }

    // Step 2: Calculate max_right[i] = max(nums[i+1]...nums[N-1])
    const maxRight = new Array(N);
    // Initialize M_R[N-1] to negative infinity as there are no elements to the right of index N-1
    maxRight[N - 1] = Number.NEGATIVE_INFINITY;
    for (let i = N - 2; i >= 0; i--) {
        maxRight[i] = Math.max(maxRight[i + 1], nums[i + 1]);
    }

    // Step 3: Determine valid elements
    const result = [];
    for (let i = 0; i < N; i++) {
        // First and last elements are always valid
        if (i === 0 || i === N - 1) {
            result.push(nums[i]);
            continue;
        }

        // Check if nums[i] is strictly greater than its left max OR strictly greater than its right max
        const isGreaterThanLeft = nums[i] > maxLeft[i];
        const isGreaterThanRight = nums[i] > maxRight[i];

        if (isGreaterThanLeft || isGreaterThanRight) {
            result.push(nums[i]);
        }
    }

    return result;
}

